import{_ as a,o as e,c as d,a2 as l}from"./chunks/framework.LN3EJxkW.js";const g=JSON.parse('{"title":"入门、初级与中级知识库","description":"","frontmatter":{},"headers":[],"relativePath":"learning-notes.md","filePath":"learning-notes.md","lastUpdated":1784382054000}'),i={name:"learning-notes.md"};function r(o,t,n,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="入门、初级与中级知识库" tabindex="-1">入门、初级与中级知识库 <a class="header-anchor" href="#入门、初级与中级知识库" aria-label="Permalink to &quot;入门、初级与中级知识库&quot;">​</a></h1><p>本页是五个方向入门、初级与中级学习笔记的统一入口。各方向的具体知识点、阅读顺序和完成状态以对应索引为准。</p><h2 id="当前覆盖" tabindex="-1">当前覆盖 <a class="header-anchor" href="#当前覆盖" aria-label="Permalink to &quot;当前覆盖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>Roadmap 覆盖范围</th><th style="text-align:right;">笔记数</th><th>知识库索引</th></tr></thead><tbody><tr><td>前端深化</td><td>阶段 0–6：Web、HTML、CSS、JavaScript、TypeScript、框架、浏览器运行时与应用架构</td><td style="text-align:right;">107</td><td><a href="./01-frontend/notes/README">前端笔记索引</a></td></tr><tr><td>产品能力</td><td>阶段 0–6：产品基础、证据与拆解、需求、MVP、PRD、指标与实验</td><td style="text-align:right;">65</td><td><a href="./02-product/notes/README">产品笔记索引</a></td></tr><tr><td>交互设计</td><td>阶段 0–5：基础原则、拆解与验证、信息架构、流程状态与交互模式</td><td style="text-align:right;">95</td><td><a href="./03-interaction-design/notes/README">交互设计笔记索引</a></td></tr><tr><td>AI 工程</td><td>阶段 0–8：模型 API、Context、AI UX、RAG、Tool、MCP、Workflow、Agent 与 Evaluation</td><td style="text-align:right;">94</td><td><a href="./04-ai/notes/README">AI 笔记索引</a></td></tr><tr><td>后端与数据</td><td>阶段 0–8：系统基础、算法、Go、网络、API、数据库、缓存、队列、搜索、存储与数据工程</td><td style="text-align:right;">84</td><td><a href="./05-backend-data/notes/README">后端与数据笔记索引</a></td></tr><tr><td><strong>合计</strong></td><td></td><td style="text-align:right;"><strong>445</strong></td><td></td></tr></tbody></table><h2 id="每篇笔记包含什么" tabindex="-1">每篇笔记包含什么 <a class="header-anchor" href="#每篇笔记包含什么" aria-label="Permalink to &quot;每篇笔记包含什么&quot;">​</a></h2><p>每个 Roadmap 独立知识点对应一篇 Markdown，内容围绕以下问题展开：</p><ul><li>是什么，解决什么问题，为什么需要学习。</li><li>关键特性、规则、约束和适用范围。</li><li>实际使用方式，包括代码、命令、SQL、分析步骤或检查清单。</li><li>常见错误、失败边界、风险和容易混淆的概念。</li><li>与该知识点直接相关的补充知识。</li><li>2–5 个官方文档、标准、论文或其他一手来源。</li></ul><p>来源链接在每篇笔记中记录访问日期。技术结论发生变化时，重新核对一手资料并运行对应示例或测试。</p><h2 id="如何学习" tabindex="-1">如何学习 <a class="header-anchor" href="#如何学习" aria-label="Permalink to &quot;如何学习&quot;">​</a></h2><ol><li>选择一个方向，从其笔记索引和 Roadmap 的第一个未掌握模块开始。</li><li>阅读笔记后运行其中的示例，记录实际输出、错误和环境差异。</li><li>完成对应练习或项目；不能独立实现、验证和排错时，不把知识点标记为完成。</li><li>将自己的理解、实验和项目证据补充到笔记，日常训练继续放在各方向的 <code>daily/</code>。</li><li>每个阶段结束后回看索引，检查知识点之间的依赖和缺口。</li></ol><h2 id="如何维护" tabindex="-1">如何维护 <a class="header-anchor" href="#如何维护" aria-label="Permalink to &quot;如何维护&quot;">​</a></h2><ul><li>路线图新增或拆分知识点时，同步新增独立笔记并更新该方向索引和覆盖数。</li><li>更新结论前优先核对官方文档、标准、论文或源码；不要只替换链接而不复核正文。</li><li>在文末保留直接来源链接并更新访问日期；容易变化的版本、兼容性和限制应明确标注。</li><li>示例必须可执行或可检查，删除已经失效的命令、API 和配置。</li><li>笔记、Roadmap 和日常记录尽量分开提交，让 Git 历史能说明变化原因。</li></ul><p>当前覆盖代表五个方向的入门、初级与中级知识库已经建立，不代表路线图停止演进。高级内容和已有知识点的更新继续沿各方向 Roadmap 补充。</p>',13)])])}const u=a(i,[["render",r]]);export{g as __pageData,u as default};
